mapper.select:
SELECT ROUND(IFNULL(MAX(g.score), 0), 2)
FROM customer_info c
         LEFT JOIN customer_group_category g ON c.group_code = g.group_code AND g.is_deleted = 0
WHERE c.is_deleted = 0
  AND c.account_status = #{accountStatus}
  AND c.manager_id = #{managerId}

SELECT ROUND(LEAST(COUNT(DISTINCT product) * 3.00, 6.00), 2)
FROM customer_info
WHERE is_deleted = 0
  AND account_status = #{accountStatus}
  AND product IS NOT NULL AND product != ''
  AND manager_id = #{managerId}

SELECT ROUND(COUNT(id) * 30.00, 2)
FROM experience_share
WHERE is_deleted = 0
  AND status = #{approveStatus}
  AND draft_status = 1
  AND emp_no = #{managerId}
